local function getCurSeasonRankData(rankId, row, col)
    local infos = SeasonRankManager.curSeasonRankData[rankId]
    if not infos then
        return ""
    end

    --table.sort(info, function(a, b)
    --    return a.rank < b.rank
    --end)

    for _, info in pairs(infos) do
        if info.rank == row then
            local index = titleText[col] or 1
            return info[index] or ""
        end
    end

    return ""
end

