local function createEntityRankById(rakssid, rankId)
    local infos = SeasonRankManager.curSeasonRankData[rankId]
    if not infos then
        return
    end

    for _, info in pairs(infos) do
        WallTextUtil.addRowWallText(rakssid, rankId, info, titleText)
    end
end

function EntityRankManager:createEntityRank(rakssid)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if not player then
        return
    end

    EntityRankManager:deleteEntityRank(rakssid)

    createEntityRankById(rakssid, 1)
    createEntityRankById(rakssid, 2)
    createEntityRankById(rakssid, 3)
    createEntityRankById(rakssid, 4)

    --LogUtil.log("EntityRankManager:createEntityRank " .. tostring(rakssid))
end

function EntityRankManager:deleteEntityRank(rakssid)
    PacketSender:sendLuaCommonData(rakssid, "DeleteAllWallText", "")
end

function EntityRankManager:updateEntityRank(lv)
    for _, vPlayer in pairs(PlayerManager:getPlayers()) do
        createEntityRankById(vPlayer.rakssid, lv)
    end
end

function EntityRankManager:delayCreateEntityRank(rakssid, delayTime)
    --LuaTimer:scheduleTimer(function()
    --    EntityRankManager:createEntityRank(rakssid)
    --end, delayTime, 1)

    EntityRankManager:createEntityRank(rakssid)
end

function EntityRankManager:onTick(ticks)
    if ticks % (1 * GameMatch.tickPerSecond) ~= 0 then
        return
    end

    local countdownTime = SeasonRankManager:getCountdownTime()
    for _, vPlayer in pairs(PlayerManager:getPlayers()) do
        EntityRankManager:updateEntityRankCountdown(vPlayer.rakssid, countdownTime)
    end
end

